#!/usr/bin/env bash
set -eo pipefail
[[ $DOKKU_TRACE ]] && set -x
source "$PLUGIN_CORE_AVAILABLE_PATH/common/functions"

config_sub() {
  declare desc="executes a config subcommand"
  local name="$1"
  shift
  "$PLUGIN_AVAILABLE_PATH/config/config_sub" "$name" "$@"
}

config_export() {
  declare desc="returns export command for config variable of specified type (app/global)"
  local CONFIG_TYPE="$1"
  shift
  local APP="$1"
  if [[ $CONFIG_TYPE == "global" ]]; then
    APP="--global"
  else
    shift
  fi
  config_sub export "$@" "$APP"
  return 0
}

config_all() {
  declare desc="Backwards compatible function for plugin use"
  [[ "$1" == "config" ]] || set -- "config" "$@"
  if [[ -n "$DOKKU_CONFIG_EXPORT" ]]; then
    config_export app "$@"
    return 0
  fi

  "$PLUGIN_AVAILABLE_PATH/config/subcommands/show" "$@"
}

config_keys() {
  declare desc="returns keys for app or global"
  config_sub keys "$@"
  return 0
}

config_get() {
  declare desc="get value of given config var"
  config_sub get "$@"
}

config_clear() {
  declare desc="clears config vars"
  config_sub clear "$@"
}

config_set() {
  declare desc="set value of given config var"
  config_sub set "$@"
}

config_unset() {
  declare desc="unset value of given config var"
  config_sub unset "$@"
}

config_bundle() {
  declare desc="export tar bundle of config"
  config_sub bundle "$@"
}

fn-config-set() {
  declare desc="set config values via trigger (supports --no-restart)"
  declare APP="$1" NO_RESTART="$2"
  shift 2
  if [[ "$NO_RESTART" == "true" ]]; then
    plugn trigger config-set --no-restart "$APP" "$@"
  else
    plugn trigger config-set "$APP" "$@"
  fi
}

#!/usr/bin/env bash
set -eo pipefail
[[ $DOKKU_TRACE ]] && set -x
source "$PLUGIN_CORE_AVAILABLE_PATH/common/functions"

cmd-plugin-list() {
  declare desc="lists all plugins"
  declare cmd="plugin"
  [[ "$1" == "$cmd" ]] && shift 1

  plugn list
}

cmd-plugin-installed() {
  declare desc="checks if a plugin is installed"
  declare cmd="plugin:installed"
  [[ "$1" == "$cmd" ]] && shift 1
  declare PLUGIN_NAME="$1"

  plugn list | awk '{print $1}' | grep -q "^${PLUGIN_NAME}$"
}

fn-plugin-set-permissions() {
  declare desc="ensures correct permissions for all available plugins"
  chown -R "${DOKKU_SYSTEM_USER}:${DOKKU_SYSTEM_GROUP}" "$PLUGIN_CORE_AVAILABLE_PATH" "$PLUGIN_AVAILABLE_PATH"
  chown -R "${DOKKU_SYSTEM_USER}:${DOKKU_SYSTEM_GROUP}" "$PLUGIN_CORE_ENABLED_PATH" "$PLUGIN_ENABLED_PATH"
}

plugin_prime_bash_completion() {
  declare desc="primes the bash-completion cache"

  dokku_log_info1_quiet "Priming bash-completion cache"
  dokku --quiet help --all | awk '/^    /{ print $1 }' | sort >"/var/cache/dokku-completion"
}

fn-is-core-plugin() {
  declare PLUGIN_NAME="$1"

  if [[ -L "$PLUGIN_CORE_ENABLED_PATH/$PLUGIN_NAME" ]]; then
    return 0
  fi

  return 1
}

fn-is-valid-plugin() {
  declare PLUGIN_NAME="$1"

  if [[ "$PLUGIN_NAME" =~ ^[0-9a-zA-Z_-]+$ ]]; then
    return 0
  fi

  return 1
}

fn-plugin-enabled() {
  declare PLUGIN_NAME="$1"

  if [[ -L "$PLUGIN_ENABLED_PATH/$PLUGIN_NAME" ]]; then
    return 0
  fi

  return 1
}
